const menu=document.querySelector('[data-menu]'),open=document.querySelector('[data-menu-open]'),close=document.querySelector('[data-menu-close]'),theme=document.querySelector('[data-theme]'),result=document.querySelector('[data-result]');let previous;function hide(){menu.close();open.setAttribute('aria-expanded','false');previous?.focus()}open?.addEventListener('click',()=>{previous=document.activeElement;menu.showModal();open.setAttribute('aria-expanded','true');close.focus()});close?.addEventListener('click',hide);menu?.addEventListener('cancel',event=>{event.preventDefault();hide()});menu?.addEventListener('click',event=>{if(event.target===menu)hide()});document.querySelectorAll('dialog a').forEach(link=>link.addEventListener('click',hide));theme?.setAttribute('aria-pressed','false');theme?.addEventListener('click',()=>{const dark=document.documentElement.dataset.theme==='dark';document.documentElement.dataset.theme=dark?'light':'dark';theme.textContent=dark?'Mörkt läge':'Ljust läge';theme.setAttribute('aria-pressed',String(!dark));theme.setAttribute('aria-label',dark?'Aktivera mörkt tema':'Aktivera ljust tema')});document.querySelector('.desk')?.insertAdjacentHTML('beforeend','<a href="#app">Appen</a>');document.querySelector('.feature-grid')?.insertAdjacentHTML('beforeend','<article><span>CHECKLISTA · DRIFT</span><h3>Varumottagning</h3><p>En konkret rutin för att ta emot leveranser med ordning.</p><a href="#resources">Se checklistan</a></article>');const candidate=document.querySelector('#tools');if(candidate){candidate.querySelector('span').textContent='FRAMTIDA VERKTYGSKANDIDAT';candidate.querySelector('p').textContent='Ett tydligt första utkast som behöver granskas och anpassas.'}document.querySelector('[data-search]')?.addEventListener('submit',event=>{event.preventDefault();const term=event.currentTarget.querySelector('input').value.trim();result.textContent=term?`Prototypresultat för ”${term}”. Sökfrasen är bevarad inför resursytan.`:'';result.tabIndex=-1;result.focus()});const style=document.createElement('style');style.textContent='[data-result]:not(:empty){margin-top:10px!important;padding:11px;border:1px solid var(--green);background:var(--paper);color:var(--ink)!important;font-weight:700}@media(max-width:899px){.actions button:first-child{display:none}}';document.head.append(style);
